const data = $input.item.json;

const appointment = data.appointment;
const client = appointment.client;

const message = {
  to: process.env.LAWYER_PHONE || '+919876543210',
  message: `New appointment request from ${client.firstName} ${client.lastName} for ${new Date(appointment.preferredDate).toLocaleDateString()} at ${appointment.preferredTime}. Description: ${appointment.description.substring(0, 100)}...`
};

return { json: message };
